class OrganizationSeeder extends Seeder { public function run(): void { $c=Company::firstOrCreate(['code'=>'ANIL'],['name'=>'آنیل','default_locale'=>'fa','default_currency'=>'IRR','timezone'=>'Asia/Tehran','is_active'=>true]); $branches=[['GOLYAS','شعبه گل‌یاس','retail_branch',true,false],['KOOHNOOR','شعبه کوه‌نور','retail_branch',true,false],['CENTRAL-WORKSHOP','کارگاه مرکزی','workshop',true,false],['PASDARAN','شعبه پاسداران','independent',false,true]]; $b=[]; foreach($branches as [$code,$name,$type,$op,$ext]) $b[$code]=Branch::firstOrCreate(['company_id'=>$c->id,'code'=>$code],['name'=>$name,'type'=>$type,'is_operational'=>$op,'is_external'=>$ext,'is_active'=>true]); $types=[['SALES','فروش',true,true,0,0,1],['RESERVE','رزرو',false,false,0,0,1],['RAW_MATERIAL','مواد اولیه',false,false,1,0,0],['WIP','در جریان تولید',false,false,0,1,0],['FINISHED_GOODS','محصول نهایی',true,true,0,0,1],['RETURNS','مرجوعی',false,false,0,0,1],['DAMAGED','ضایعات',false,false,0,0,0],['CONSIGNMENT','امانی',true,true,0,0,1],['OTHER','سایر',false,false,0,0,0]]; $t=[]; foreach($types as $x) $t[$x[0]]=WarehouseType::firstOrCreate(['company_id'=>$c->id,'code'=>$x[0]],['name'=>$x[1],'is_sellable'=>$x[2],'is_shippable'=>$x[3],'supports_raw_materials'=>$x[4],'supports_work_in_progress'=>$x[5],'supports_finished_goods'=>$x[6]]); $wh=[['GOLYAS-SALES','انبار فروشگاه گل‌یاس','GOLYAS','SALES'],['GOLYAS-RESERVE','انبار پشتیبان گل‌یاس','GOLYAS','RESERVE'],['GOLYAS-RETURNS','انبار مرجوعی گل‌یاس','GOLYAS','RETURNS'],['KOOHNOOR-SALES','انبار فروشگاه کوه‌نور','KOOHNOOR','SALES'],['KOOHNOOR-RESERVE','انبار پشتیبان کوه‌نور','KOOHNOOR','RESERVE'],['FABRIC','انبار پارچه','CENTRAL-WORKSHOP','RAW_MATERIAL'],['RAW','انبار مواد اولیه','CENTRAL-WORKSHOP','RAW_MATERIAL'],['WIP','کالای در جریان تولید','CENTRAL-WORKSHOP','WIP'],['FG','انبار محصول نهایی','CENTRAL-WORKSHOP','FINISHED_GOODS'],['SCRAP','انبار ضایعات','CENTRAL-WORKSHOP','DAMAGED']]; foreach($wh as [$code,$name,$br,$ty]) Warehouse::firstOrCreate(['company_id'=>$c->id,'code'=>$code],['name'=>$name,'branch_id'=>$b[$br]->id,'warehouse_type_id'=>$t[$ty]->id,'is_sellable'=>$t[$ty]->is_sellable,'is_shippable'=>$t[$ty]->is_shippable]); $chs=[['GOLYAS-POS','فروش حضوری گل‌یاس','physical_store','GOLYAS',false],['KOOHNOOR-POS','فروش حضوری کوه‌نور','physical_store','KOOHNOOR',false],['WEBSITE','سایت','website',null,true],['INSTAGRAM','اینستاگرام','social',null,true],['BALE','بله','social',null,true],['EXHIBITION','نمایشگاه','exhibition',null,true],['WHOLESALE','فروش عمده','wholesale',null,true],['ORG','فروش سازمانی','organizational',null,true],['CONSIGNMENT','فروش امانی','consignment',null,true]]; foreach($chs as [$code,$name,$type,$br,$req]) SalesChannel::firstOrCreate(['company_id'=>$c->id,'code'=>$code],['name'=>$name,'type'=>$type,'branch_id'=>$br?$b[$br]->id:null,'requires_warehouse_selection'=>$req]); } }
